'use strict';
/**
 * REGRESSION — FRG-243
 * Characters play contextual animations during interactions.
 *
 * Tests run against the local dev server (http://localhost:3000) because this
 * feature lives in the feature/frg-243-contextual-interaction-animations branch,
 * not yet deployed to Vercel.
 *
 * The page does NOT expose window._gameEngine by default, so we intercept
 * index.html via page.route() and inject the exposure before the script executes.
 *
 * Test layout:
 *   1. _getInteractAnim mapping — book/desk/bookshelf→reading, bed/kotatsu/sofa/tv→sit, others→phone
 *   2. Sprite key during interaction — startInteraction sets spriteKey + interactAnim correctly
 *   3. Animation clears after timer — interactAnim null + spriteKey reverts to idle after 2000ms
 *   4. Live sim regression — natural interaction uses a contextual spriteKey (_reading|_sit|_phone)
 *   5. All 9 interaction sprites load without network errors
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:3000';

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Intercept index.html served at / and inject:
 *   window._gameEngine = engine
 *   window.SimulationEngine = SimulationEngine
 * so tests can access the engine and its static methods via page.evaluate().
 */
async function injectEngineExposure(page) {
  await page.route('**/', async (route) => {
    const response = await route.fetch();
    let body = await response.text();
    body = body.replace(
      '// ── Initial state ──',
      '// ── Initial state (QA injection) ──\nwindow._gameEngine = engine;\nwindow.SimulationEngine = SimulationEngine;'
    );
    await route.fulfill({ response, body });
  });
}

/**
 * Click the start overlay (if visible) and optionally boost time scale.
 */
async function startEngine(page, timeScale = 20) {
  const overlay = page.locator('#start-overlay');
  if (await overlay.isVisible()) {
    await overlay.click();
  }
  await page.evaluate((scale) => {
    if (window._gameEngine) window._gameEngine.timeScale = scale;
  }, timeScale);
}

/**
 * Poll character states until predicate returns truthy or timeout.
 * Returns the last character state array that satisfied the predicate.
 */
async function pollCharState(page, predicate, timeoutMs = 45_000, intervalMs = 300) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const chars = await page.evaluate(() =>
      window._gameEngine.characters.map(c => ({
        id: c.id,
        action: c.action,
        interactAnim: c.interactAnim,
        spriteKey: c.spriteKey,
        targetObjectId: c.targetObjectId,
      }))
    );
    if (predicate(chars)) return chars;
    await page.waitForTimeout(intervalMs);
  }
  throw new Error(`pollCharState timed out after ${timeoutMs}ms`);
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-243: Contextual Interaction Animations', () => {

  // ── TEST 1: _getInteractAnim mapping ──────────────────────────────────────

  test('_getInteractAnim maps object IDs to the correct animation', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window.SimulationEngine != null, { timeout: 15_000 });

    const results = await page.evaluate(() => {
      const fn = window.SimulationEngine._getInteractAnim.bind(window.SimulationEngine);
      return [
        // book / desk / bookshelf → 'reading'
        { id: 'bookshelf_1',       expected: 'reading', actual: fn('bookshelf_1') },
        { id: 'book_closed',       expected: 'reading', actual: fn('book_closed') },
        { id: 'book_open',         expected: 'reading', actual: fn('book_open') },
        { id: 'desk',              expected: 'reading', actual: fn('desk') },
        { id: 'study_desk_north',  expected: 'reading', actual: fn('study_desk_north') },

        // bed / kotatsu / sofa / tv → 'sit'
        { id: 'bed',               expected: 'sit',     actual: fn('bed') },
        { id: 'kotatsu',           expected: 'sit',     actual: fn('kotatsu') },
        { id: 'living_sofa_left',  expected: 'sit',     actual: fn('living_sofa_left') },
        { id: 'tv',                expected: 'sit',     actual: fn('tv') },
        { id: 'bedroom_bed_main',  expected: 'sit',     actual: fn('bedroom_bed_main') },

        // all other objects → 'phone'
        { id: 'cafe_espresso',     expected: 'phone',   actual: fn('cafe_espresso') },
        { id: 'fridge',            expected: 'phone',   actual: fn('fridge') },
        { id: 'sink',              expected: 'phone',   actual: fn('sink') },
        { id: 'cash_register',     expected: 'phone',   actual: fn('cash_register') },
        { id: 'easel_blank',       expected: 'phone',   actual: fn('easel_blank') },
      ];
    });

    for (const r of results) {
      console.log(`_getInteractAnim('${r.id}'): expected=${r.expected}, actual=${r.actual}`);
      expect(r.actual, `_getInteractAnim('${r.id}') should return '${r.expected}'`).toBe(r.expected);
    }
  });

  // ── TEST 2: spriteKey and interactAnim change during interaction ──────────

  test('startInteraction sets spriteKey and interactAnim correctly', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;
      const chars = engine.characters;

      const maple = chars.find(c => c.id === 'maple');
      const sol   = chars.find(c => c.id === 'sol');
      const nyx   = chars.find(c => c.id === 'nyx');

      // Test each character with a different animation type
      maple.startInteraction('bookshelf_1', 'reading');
      sol.startInteraction('kotatsu', 'sit');
      nyx.startInteraction('cafe_espresso', 'phone');

      return [
        {
          charId: 'maple',
          objectId: 'bookshelf_1',
          anim: 'reading',
          interactAnim: maple.interactAnim,
          spriteKey: maple.spriteKey,
          action: maple.action,
        },
        {
          charId: 'sol',
          objectId: 'kotatsu',
          anim: 'sit',
          interactAnim: sol.interactAnim,
          spriteKey: sol.spriteKey,
          action: sol.action,
        },
        {
          charId: 'nyx',
          objectId: 'cafe_espresso',
          anim: 'phone',
          interactAnim: nyx.interactAnim,
          spriteKey: nyx.spriteKey,
          action: nyx.action,
        },
      ];
    });

    for (const r of results) {
      console.log(
        `${r.charId}: action=${r.action}, interactAnim=${r.interactAnim}, spriteKey=${r.spriteKey}`
      );
      expect(r.action, `${r.charId} action should be 'interacting'`).toBe('interacting');
      expect(r.interactAnim, `${r.charId} interactAnim should be '${r.anim}'`).toBe(r.anim);
      expect(r.spriteKey, `${r.charId} spriteKey should be '${r.charId}_${r.anim}'`).toBe(`${r.charId}_${r.anim}`);
    }
  });

  // ── TEST 3: interactAnim clears after timer expires ────────────────────────

  test('interactAnim clears and spriteKey reverts to idle after interaction ends', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const maple = engine.characters.find(c => c.id === 'maple');

      // Put maple into an interaction
      maple.startInteraction('bookshelf_1', 'reading');

      const during = {
        action:      maple.action,
        interactAnim: maple.interactAnim,
        spriteKey:   maple.spriteKey,
      };

      // Advance the engine past the 2000ms interaction timer
      engine._updateCharacters(2001);

      const after = {
        action:      maple.action,
        interactAnim: maple.interactAnim,
        spriteKey:   maple.spriteKey,
      };

      return { during, after };
    });

    // During interaction
    console.log('During interaction:', JSON.stringify(result.during));
    expect(result.during.action).toBe('interacting');
    expect(result.during.interactAnim).toBe('reading');
    expect(result.during.spriteKey).toBe('maple_reading');

    // After timer expires
    console.log('After timer expiry:', JSON.stringify(result.after));
    expect(result.after.action, 'action should revert to idle').toBe('idle');
    expect(result.after.interactAnim, 'interactAnim should be null after interaction ends').toBeNull();
    expect(result.after.spriteKey, 'spriteKey should revert to maple_idle').toBe('maple_idle');
  });

  // ── TEST 4: Live sim — natural interaction uses contextual spriteKey ───────

  test('interacting character uses a contextual spriteKey in the live sim', async ({ page }) => {
    test.setTimeout(90_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });
    await startEngine(page, 20);

    const CONTEXTUAL_SUFFIXES = ['_reading', '_sit', '_phone'];

    // Poll until any character is interacting with a contextual spriteKey
    const chars = await pollCharState(
      page,
      cs => cs.some(
        c => c.action === 'interacting' &&
             c.interactAnim !== null &&
             CONTEXTUAL_SUFFIXES.some(suffix => c.spriteKey.endsWith(suffix))
      ),
      60_000
    );

    const interacting = chars.filter(
      c => c.action === 'interacting' &&
           c.interactAnim !== null &&
           CONTEXTUAL_SUFFIXES.some(suffix => c.spriteKey.endsWith(suffix))
    );

    console.log('Interacting with contextual anim:', interacting.map(c =>
      `${c.id}: spriteKey=${c.spriteKey}, interactAnim=${c.interactAnim}, target=${c.targetObjectId}`
    ).join(' | '));

    expect(interacting.length, 'At least one character should use a contextual spriteKey').toBeGreaterThanOrEqual(1);

    for (const c of interacting) {
      expect(
        CONTEXTUAL_SUFFIXES.some(suffix => c.spriteKey.endsWith(suffix)),
        `${c.id} spriteKey '${c.spriteKey}' should end with _reading, _sit, or _phone`
      ).toBe(true);
    }
  });

  // ── TEST 5: All 9 interaction sprites load without errors ─────────────────

  test('all 9 interaction sprites load without network errors', async ({ page }) => {
    test.setTimeout(30_000);

    const EXPECTED_SPRITES = [
      'maple_reading', 'maple_sit', 'maple_phone',
      'sol_reading',   'sol_sit',   'sol_phone',
      'nyx_reading',   'nyx_sit',   'nyx_phone',
    ];

    const spriteResults = {};

    page.on('response', response => {
      const url = response.url();
      for (const key of EXPECTED_SPRITES) {
        if (url.includes(`${key}.png`)) {
          spriteResults[key] = response.status();
        }
      }
    });

    await page.goto(LOCAL_URL);

    // Wait for sprite preload — the preloadSprites() promise resolves before
    // the render loop starts; 5s is ample for a local server
    await page.waitForTimeout(5_000);

    for (const key of EXPECTED_SPRITES) {
      console.log(`Sprite ${key}.png: status=${spriteResults[key] ?? 'not requested'}`);
      expect(spriteResults[key], `${key}.png should have been requested`).toBeDefined();
      expect(spriteResults[key], `${key}.png should return HTTP 200`).toBe(200);
    }
  });
});

