  },
  {
    id: 'tea_set',
    name: 'tea set',
    capacity: 1,
    interactAnim: 'phone',
    position: { tx: 5, ty: 5 },
    interactMs: 6000,
    state: 'idle',
    spriteMap: { idle: 'cup_empty', brewing: 'cup_full', ready: 'cup_full' },
    states: {
      idle: {
        transitions: { use: { next: 'brewing' } },
      },
      brewing: {
        speech: 'Brewing some tea~',
        auto_next: { state: 'ready', after: 15 },
      },
      ready: {
        emoji: '🍵',
        speech: 'Tea is ready~',
        auto_next: { state: 'idle', after: 45 },
        transitions: { use: { next: 'idle' } },
      },
    },
  },
  {
    id: 'kotatsu',
