    test.setTimeout(30_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;
      const objects = engine.objectEngine.getAll();
      const byId = {};
      for (const o of objects) byId[o.id] = o;

      return {
        stove: {
          hasSpriteMap:  byId.stove?.spriteMap != null,
          idle:          byId.stove?.spriteMap?.idle,
          cooking:       byId.stove?.spriteMap?.cooking,
          done:          byId.stove?.spriteMap?.done,
