'use strict';
/**
 * REGRESSION — FRG-246
 * Objects change sprite when state transitions.
 *
 * Tests run against the local dev server (http://localhost:5176) which serves
 * the master branch of the source repository.
 *
 * window._gameEngine is set unconditionally in scene.js create() — no route
 * injection needed.
 *
 * Key implementation under test:
 *   - OBJECT_DEFS in src/objects.js: stove, tea_set, bookshelf, easel have spriteMap
 *   - ObjectInstance.interact() returns { spriteKey } matching the new state's entry
 *   - ObjectInstance.tick()     returns { spriteKey } on auto-transition
 *   - scene.js creates this._objectSprites[id] images (depth=1, origin(0,0))
 *   - scene.update() swaps texture via setTexture(ev.spriteKey) from pendingEvents
 *
 * spriteMap definitions:
 *   stove:     { idle: 'stove_off',    cooking: 'stove_on',        done: 'stove_on'        }
 *   tea_set:   { idle: 'cup_empty',    brewing: 'cup_full',        ready: 'cup_full'       }
 *   bookshelf: { idle: 'book_closed',  reading: 'book_open'                                }
 *   easel:     { idle: 'easel_blank',  painting: 'easel_painting', done: 'easel_finished'  }
 *
 * Test layout:
 *   1. spriteMap defined on stove, tea_set, bookshelf, easel — correct keys and idle sprites
 *   2. interact() returns spriteKey matching new state; null for objects without spriteMap
 *   3. tick() auto-transition returns correct spriteKey
 *   4. Scene creates _objectSprites with depth=1 and origin(0,0), initial texture = idle sprite
 *   5. Sprite texture swaps on interact event; swaps back to idle on return transition
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:5176';

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Wait for the SimulationEngine to be fully initialised with 3 characters.
 */
async function waitForEngine(page) {
  await page.waitForFunction(
    () => window._gameEngine?.characters?.length === 3,
    { timeout: 15_000 }
  );
}

/**
 * Intercept scene.js to inject window._gameScene = this inside create().
 * This lets tests access _objectSprites from the CafeScene instance.
 */
async function injectSceneExposure(page) {
  await page.route('**/scene.js*', async (route) => {
    const response = await route.fetch();
    let body = await response.text();
    body = body.replace(
      'window._gameEngine = this.engine;',
      'window._gameEngine = this.engine;\n    window._gameScene = this;'
    );
    await route.fulfill({ response, body });
  });
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-246: Object Sprite Swap on State Transition', () => {

  // ── TEST 1: spriteMap defined on all 4 mapped objects ────────────────────────

  test('spriteMap is defined on stove, tea_set, bookshelf, and easel with correct entries', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;
      const objects = engine.objectEngine.getAll();
      const byId = {};
      for (const o of objects) byId[o.id] = o;

      return {
        stove: {
          hasSpriteMap:  byId.stove?.spriteMap != null,
          idle:          byId.stove?.spriteMap?.idle,
          cooking:       byId.stove?.spriteMap?.cooking,
          done:          byId.stove?.spriteMap?.done,
        },
        tea_set: {
          hasSpriteMap:  byId.tea_set?.spriteMap != null,
          idle:          byId.tea_set?.spriteMap?.idle,
          brewing:       byId.tea_set?.spriteMap?.brewing,
          ready:         byId.tea_set?.spriteMap?.ready,
        },
        bookshelf: {
          hasSpriteMap:  byId.bookshelf?.spriteMap != null,
          idle:          byId.bookshelf?.spriteMap?.idle,
          reading:       byId.bookshelf?.spriteMap?.reading,
        },
        easel: {
          hasSpriteMap:  byId.easel?.spriteMap != null,
          idle:          byId.easel?.spriteMap?.idle,
          painting:      byId.easel?.spriteMap?.painting,
          done:          byId.easel?.spriteMap?.done,
        },
        // Objects without a spriteMap
        fridge: {
          hasSpriteMap:  byId.fridge?.spriteMap != null,
        },
        kotatsu: {
          hasSpriteMap:  byId.kotatsu?.spriteMap != null,
        },
        bonsai: {
          hasSpriteMap:  byId.bonsai?.spriteMap != null,
        },
      };
    });

    console.log('spriteMap results:', JSON.stringify(results, null, 2));

    // stove
    expect(results.stove.hasSpriteMap, 'stove should have a spriteMap').toBe(true);
    expect(results.stove.idle,    'stove idle sprite').toBe('stove_off');
    expect(results.stove.cooking, 'stove cooking sprite').toBe('stove_on');
    expect(results.stove.done,    'stove done sprite').toBe('stove_on');

    // tea_set
    expect(results.tea_set.hasSpriteMap, 'tea_set should have a spriteMap').toBe(true);
    expect(results.tea_set.idle,    'tea_set idle sprite').toBe('cup_empty');
    expect(results.tea_set.brewing, 'tea_set brewing sprite').toBe('cup_full');
    expect(results.tea_set.ready,   'tea_set ready sprite').toBe('cup_full');

    // bookshelf
    expect(results.bookshelf.hasSpriteMap, 'bookshelf should have a spriteMap').toBe(true);
    expect(results.bookshelf.idle,    'bookshelf idle sprite').toBe('book_closed');
    expect(results.bookshelf.reading, 'bookshelf reading sprite').toBe('book_open');

    // easel
    expect(results.easel.hasSpriteMap, 'easel should have a spriteMap').toBe(true);
    expect(results.easel.idle,     'easel idle sprite').toBe('easel_blank');
    expect(results.easel.painting, 'easel painting sprite').toBe('easel_painting');
    expect(results.easel.done,     'easel done sprite').toBe('easel_finished');

    // Objects without spriteMap should return null
    expect(results.fridge.hasSpriteMap,  'fridge should NOT have a spriteMap').toBe(false);
    expect(results.kotatsu.hasSpriteMap, 'kotatsu should NOT have a spriteMap').toBe(false);
    expect(results.bonsai.hasSpriteMap,  'bonsai should NOT have a spriteMap').toBe(false);
  });

  // ── TEST 2: interact() returns spriteKey ─────────────────────────────────────

  test('interact() returns spriteKey for mapped objects and null for unmapped objects', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;

      // stove: idle → cooking (spriteKey: 'stove_on')
      const stove = engine.objectEngine.getById('stove');
      const stoveEv = stove.interact('use');

      // tea_set: idle → brewing (spriteKey: 'cup_full')
      const teaSet = engine.objectEngine.getById('tea_set');
      const teaEv = teaSet.interact('use');

      // bookshelf: idle → reading (spriteKey: 'book_open')
      const bookshelf = engine.objectEngine.getById('bookshelf');
      const bookEv = bookshelf.interact('use');

      // easel: idle → painting (spriteKey: 'easel_painting')
      const easel = engine.objectEngine.getById('easel');
      const easelEv = easel.interact('use');

      // fridge: idle → open (no spriteMap → spriteKey null/undefined)
      const fridge = engine.objectEngine.getById('fridge');
      const fridgeEv = fridge.interact('use');

      // bonsai: idle → tending (no spriteMap)
      const bonsai = engine.objectEngine.getById('bonsai');
      const bonsaiEv = bonsai.interact('use');

      return {
        stove:     { state: stoveEv?.state,     spriteKey: stoveEv?.spriteKey     },
        teaSet:    { state: teaEv?.state,        spriteKey: teaEv?.spriteKey       },
        bookshelf: { state: bookEv?.state,       spriteKey: bookEv?.spriteKey      },
        easel:     { state: easelEv?.state,      spriteKey: easelEv?.spriteKey     },
        fridge:    { state: fridgeEv?.state,     spriteKey: fridgeEv?.spriteKey    },
        bonsai:    { state: bonsaiEv?.state,     spriteKey: bonsaiEv?.spriteKey    },
      };
    });

    console.log('interact() spriteKey results:', JSON.stringify(results));

    // Mapped objects: spriteKey should match the new state's sprite
    expect(results.stove.state,         'stove state after interact').toBe('cooking');
    expect(results.stove.spriteKey,     'stove spriteKey after interact').toBe('stove_on');

    expect(results.teaSet.state,        'tea_set state after interact').toBe('brewing');
    expect(results.teaSet.spriteKey,    'tea_set spriteKey after interact').toBe('cup_full');

    expect(results.bookshelf.state,     'bookshelf state after interact').toBe('reading');
    expect(results.bookshelf.spriteKey, 'bookshelf spriteKey after interact').toBe('book_open');

    expect(results.easel.state,         'easel state after interact').toBe('painting');
    expect(results.easel.spriteKey,     'easel spriteKey after interact').toBe('easel_painting');

    // Unmapped objects: spriteKey should be null or undefined (falsy)
    expect(results.fridge.state,        'fridge state after interact').toBe('open');
    expect(results.fridge.spriteKey ?? null, 'fridge spriteKey should be null (no spriteMap)').toBeNull();

    expect(results.bonsai.state,        'bonsai state after interact').toBe('tending');
    expect(results.bonsai.spriteKey ?? null, 'bonsai spriteKey should be null (no spriteMap)').toBeNull();
  });

  // ── TEST 3: tick() auto-transition returns spriteKey ─────────────────────────

  test('tick() returns spriteKey on auto-transition for mapped objects', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;

      // ── bookshelf: idle → reading (via interact), then reading → idle (via tick) ──
      const bookshelf = engine.objectEngine.getById('bookshelf');
      // Put bookshelf into 'reading' state (auto_next: idle after 40s)
      bookshelf.interact('use'); // idle → reading
      // Fast-forward the auto timer to trigger the reading → idle transition
      bookshelf.autoTimer = 1; // 1ms remaining
      const bookTickEv = bookshelf.tick(100); // 100ms delta → timer expires

      // ── stove: cooking → done (via tick, auto_next: done after 30s) ──
      const stove = engine.objectEngine.getById('stove');
      stove.interact('use'); // idle → cooking (sets autoTimer = 30 * 1000)
      stove.autoTimer = 1;   // fast-forward
      const stoveCookingToDoneEv = stove.tick(100); // cooking → done

      // ── stove: done → idle (via tick, auto_next: idle after 60s) ──
      stove.autoTimer = 1;
      const stoneDoneToIdleEv = stove.tick(100); // done → idle

      // ── easel: painting → done (via tick, auto_next: done after 45s) ──
      const easel = engine.objectEngine.getById('easel');
      easel.interact('use'); // idle → painting
      easel.autoTimer = 1;
      const easelPaintingToDoneEv = easel.tick(100); // painting → done

      // ── fridge (no spriteMap): open → idle (via tick) ──
      const fridge = engine.objectEngine.getById('fridge');
      fridge.interact('use'); // idle → open (auto_next: idle after 10s)
      fridge.autoTimer = 1;
      const fridgeTickEv = fridge.tick(100); // open → idle

      return {
        book_readingToIdle: {
          state:     bookTickEv?.state,
          auto:      bookTickEv?.auto,
          spriteKey: bookTickEv?.spriteKey,
        },
        stove_cookingToDone: {
          state:     stoveCookingToDoneEv?.state,
          auto:      stoveCookingToDoneEv?.auto,
          spriteKey: stoveCookingToDoneEv?.spriteKey,
        },
        stove_doneToIdle: {
          state:     stoneDoneToIdleEv?.state,
          auto:      stoneDoneToIdleEv?.auto,
          spriteKey: stoneDoneToIdleEv?.spriteKey,
        },
        easel_paintingToDone: {
          state:     easelPaintingToDoneEv?.state,
          auto:      easelPaintingToDoneEv?.auto,
          spriteKey: easelPaintingToDoneEv?.spriteKey,
        },
        fridge_openToIdle: {
          state:     fridgeTickEv?.state,
          auto:      fridgeTickEv?.auto,
          spriteKey: fridgeTickEv?.spriteKey,
        },
      };
    });

    console.log('tick() spriteKey results:', JSON.stringify(results, null, 2));

    // bookshelf: reading → idle auto-transition
    expect(results.book_readingToIdle.state,     'bookshelf auto → idle state').toBe('idle');
    expect(results.book_readingToIdle.auto,       'bookshelf tick event should be auto').toBe(true);
    expect(results.book_readingToIdle.spriteKey,  'bookshelf idle sprite via tick').toBe('book_closed');

    // stove: cooking → done auto-transition (both map to stove_on)
    expect(results.stove_cookingToDone.state,     'stove auto → done state').toBe('done');
    expect(results.stove_cookingToDone.auto,       'stove cooking→done tick event should be auto').toBe(true);
    expect(results.stove_cookingToDone.spriteKey,  'stove done sprite via tick').toBe('stove_on');

    // stove: done → idle auto-transition (returns to stove_off)
    expect(results.stove_doneToIdle.state,         'stove auto → idle state').toBe('idle');
    expect(results.stove_doneToIdle.auto,           'stove done→idle tick event should be auto').toBe(true);
    expect(results.stove_doneToIdle.spriteKey,      'stove idle sprite via tick').toBe('stove_off');

    // easel: painting → done auto-transition
    expect(results.easel_paintingToDone.state,     'easel auto → done state').toBe('done');
    expect(results.easel_paintingToDone.auto,       'easel painting→done tick event should be auto').toBe(true);
    expect(results.easel_paintingToDone.spriteKey,  'easel done sprite via tick').toBe('easel_finished');

    // fridge (no spriteMap): tick event should have null/undefined spriteKey
    expect(results.fridge_openToIdle.state,        'fridge auto → idle state').toBe('idle');
    expect(results.fridge_openToIdle.auto,          'fridge tick event should be auto').toBe(true);
    expect(results.fridge_openToIdle.spriteKey ?? null, 'fridge tick spriteKey should be null').toBeNull();
  });

  // ── TEST 4: Scene renders object sprite overlays ──────────────────────────────

  test('scene creates _objectSprites for mapped objects at depth=1 with origin(0,0) and idle texture', async ({ page }) => {
    test.setTimeout(30_000);

    await injectSceneExposure(page);
    await page.goto(LOCAL_URL);
    await waitForEngine(page);

    // Give Phaser one extra RAF cycle to finish create()
    await page.waitForTimeout(500);

    const result = await page.evaluate(() => {
      const scene = window._gameScene;
      if (!scene || !scene._objectSprites) {
        return { error: '_objectSprites not found on scene' };
      }

      const TILE_SIZE = 48;
      const spriteIds = Object.keys(scene._objectSprites);

      const details = {};
      for (const id of spriteIds) {
        const img = scene._objectSprites[id];
        const engine = window._gameEngine;
        const obj = engine.objectEngine.getById(id);
        const expectedX = obj?.tx != null ? obj.tx * TILE_SIZE : null;
        const expectedY = obj?.ty != null ? obj.ty * TILE_SIZE : null;
        details[id] = {
          textureKey: img.texture?.key,
          depth:      img.depth,
          originX:    img.originX,
          originY:    img.originY,
          x:          img.x,
          y:          img.y,
          expectedX,
          expectedY,
        };
      }

      return { spriteIds, details };
    });

    console.log('_objectSprites result:', JSON.stringify(result, null, 2));

    // Should not have an error
    expect(result.error, result.error).toBeUndefined();

    // All 4 mapped objects must have sprite entries
    const MAPPED_IDS = ['stove', 'tea_set', 'bookshelf', 'easel'];
    for (const id of MAPPED_IDS) {
      expect(result.spriteIds, `_objectSprites should contain '${id}'`).toContain(id);
    }

    // No entries for unmapped objects
    const UNMAPPED_IDS = ['fridge', 'kotatsu', 'bonsai', 'desk', 'bed', 'tv'];
    for (const id of UNMAPPED_IDS) {
      expect(result.spriteIds, `_objectSprites should NOT contain '${id}'`).not.toContain(id);
    }

    // Verify depth, origin, position, and initial texture for each mapped object
    const EXPECTED_IDLE_SPRITES = {
      stove:     'stove_off',
      tea_set:   'cup_empty',
      bookshelf: 'book_closed',
      easel:     'easel_blank',
    };

    for (const id of MAPPED_IDS) {
      const d = result.details[id];
      expect(d.depth,   `${id} sprite depth should be 1`).toBe(1);
      expect(d.originX, `${id} sprite originX should be 0`).toBe(0);
      expect(d.originY, `${id} sprite originY should be 0`).toBe(0);
      expect(d.textureKey,
        `${id} initial texture should be the idle sprite '${EXPECTED_IDLE_SPRITES[id]}'`
      ).toBe(EXPECTED_IDLE_SPRITES[id]);
      // Position should match object tile * TILE_SIZE
      expect(d.x, `${id} sprite x should be tx*48`).toBe(d.expectedX);
      expect(d.y, `${id} sprite y should be ty*48`).toBe(d.expectedY);
    }
  });

  // ── TEST 5: Sprite texture swaps on state transition (live sim) ───────────────

  test('_objectSprites texture swaps on state transition and reverts to idle on return', async ({ page }) => {
    test.setTimeout(30_000);

    await injectSceneExposure(page);
    await page.goto(LOCAL_URL);
    await waitForEngine(page);
    await page.waitForTimeout(500); // let Phaser create() complete

    // ── 5a: Check initial textures ────────────────────────────────────────────
    const initialTextures = await page.evaluate(() => {
      const scene = window._gameScene;
      return {
        stove:     scene._objectSprites?.stove?.texture?.key,
        tea_set:   scene._objectSprites?.tea_set?.texture?.key,
        bookshelf: scene._objectSprites?.bookshelf?.texture?.key,
        easel:     scene._objectSprites?.easel?.texture?.key,
      };
    });

    console.log('Initial textures:', JSON.stringify(initialTextures));
    expect(initialTextures.stove,     'stove initial texture').toBe('stove_off');
    expect(initialTextures.tea_set,   'tea_set initial texture').toBe('cup_empty');
    expect(initialTextures.bookshelf, 'bookshelf initial texture').toBe('book_closed');
    expect(initialTextures.easel,     'easel initial texture').toBe('easel_blank');

    // ── 5b: Trigger interact → cooking, push spriteKey event to pendingEvents ──
    await page.evaluate(() => {
      const engine = window._gameEngine;
      // Interact with stove: idle → cooking
      const ev = engine.objectEngine.interact('stove', 'use');
      // Push the event so scene.update() picks it up on the next RAF
      if (ev) engine.pendingEvents.push(ev);
    });

    // Wait for Phaser's RAF loop to call scene.update() and process pendingEvents
    await page.waitForTimeout(500);

    const afterCookingTexture = await page.evaluate(() => {
      const scene = window._gameScene;
      return scene._objectSprites?.stove?.texture?.key;
    });

    console.log('Stove texture after idle→cooking interact:', afterCookingTexture);
    expect(afterCookingTexture,
      'stove texture should be stove_on after transitioning to cooking'
    ).toBe('stove_on');

    // ── 5c: Auto-tick stove through done → idle, verify texture reverts ────────
    await page.evaluate(() => {
      const engine = window._gameEngine;
      const stove = engine.objectEngine.getById('stove');

      // Fast-forward: cooking → done via auto timer
      stove.autoTimer = 1;
      const ev1 = stove.tick(100); // cooking → done (spriteKey: 'stove_on', same visual)
      if (ev1?.spriteKey) engine.pendingEvents.push(ev1);

      // Fast-forward: done → idle via auto timer
      stove.autoTimer = 1;
      const ev2 = stove.tick(100); // done → idle (spriteKey: 'stove_off')
      if (ev2?.spriteKey) engine.pendingEvents.push(ev2);
    });

    // Wait for RAF to process both events
    await page.waitForTimeout(500);

    const afterIdleTexture = await page.evaluate(() => {
      const scene = window._gameScene;
      return scene._objectSprites?.stove?.texture?.key;
    });

    console.log('Stove texture after returning to idle:', afterIdleTexture);
    expect(afterIdleTexture,
      'stove texture should revert to stove_off after returning to idle'
    ).toBe('stove_off');

    // ── 5d: Verify bookshelf swap (idle→reading→idle) ──────────────────────────
    await page.evaluate(() => {
      const engine = window._gameEngine;
      const bookshelf = engine.objectEngine.getById('bookshelf');

      // idle → reading
      const ev1 = bookshelf.interact('use');
      if (ev1?.spriteKey) engine.pendingEvents.push(ev1);
    });

    await page.waitForTimeout(500);

    const bookshelfReadingTexture = await page.evaluate(() => {
      const scene = window.Phaser?.GAMES?.[0]?.scene?.scenes?.[0];
      return scene._objectSprites?.bookshelf?.texture?.key;
    });

    console.log('Bookshelf texture after idle→reading:', bookshelfReadingTexture);
    expect(bookshelfReadingTexture,
      'bookshelf texture should be book_open after transitioning to reading'
    ).toBe('book_open');

    await page.evaluate(() => {
      const engine = window._gameEngine;
      const bookshelf = engine.objectEngine.getById('bookshelf');

      // reading → idle via auto timer
      bookshelf.autoTimer = 1;
      const ev2 = bookshelf.tick(100);
      if (ev2?.spriteKey) engine.pendingEvents.push(ev2);
    });

    await page.waitForTimeout(500);

    const bookshelfIdleTexture = await page.evaluate(() => {
      const scene = window.Phaser?.GAMES?.[0]?.scene?.scenes?.[0];
      return scene._objectSprites?.bookshelf?.texture?.key;
    });

    console.log('Bookshelf texture after reading→idle:', bookshelfIdleTexture);
    expect(bookshelfIdleTexture,
      'bookshelf texture should revert to book_closed after returning to idle'
    ).toBe('book_closed');
  });
});

